58	.fact-item{background:var(--card);padding:6px 10px;border-radius:6px;margin-bottom:4px;font-size:.78rem}
59	.fact-id{color:var(--muted);font-size:.7rem}
60	.empty{color:var(--muted);text-align:center;padding:20px;font-size:.85rem}
61	.live-view{display:flex;flex-direction:column;height:calc(100vh - 80px)}
62	.live-body{flex:1;overflow-y:auto;padding:12px;font-family:'Courier New',monospace;font-size:.75rem;line-height:1.5;white-space:pre-wrap;word-break:break-all;background:var(--card);border-radius:8px}
63	.live-body .chunk{margin-bottom:2px}
64	.live-body .chunk.thought{color:#a78bfa}
65	.live-body .chunk.tool{color:var(--yellow)}
66	.live-footer{padding:8px 0;font-size:.75rem;color:var(--muted);display:flex;justify-content:space-between;align-items:center}
67	.cancel-btn{background:var(--red);color:#fff;border:none;border-radius:4px;padding:4px 10px;font-size:.75rem;cursor:pointer}
68	</style>
69	</head>
70	<body>
71	<div class="container">
72	  <h1><span class="dot"></span> Specialist Dashboard</h1>
73	  <div id="app"></div>
74	</div>
75	<script>
76	const API = location.origin;
77	const app = document.getElementById('app');
78	let pollTimer = null;
79	let eventSource = null;
80	let autoScroll = true;
81	
82	// ─── Router ──────────────────────────────────────────────────────────────────
83	function navigate(hash) { location.hash = hash; }
84	function getRoute() {
85	  const h = location.hash || '#/';
86	  const spMatch = h.match(/^#\/specialist\/(.+)$/);
87	  if (spMatch) return { page: 'specialist', name: decodeURIComponent(spMatch[1]) };
88	  const taskMatch = h.match(/^#\/task\/(.+)$/);
89	  if (taskMatch) return { page: 'task', taskId: decodeURIComponent(taskMatch[1]) };
90	  return { page: 'dashboard' };
91	}
92	window.addEventListener('hashchange', () => route());
93	function route() {
94	  stopPolling();
95	  if (eventSource) { eventSource.close(); eventSource = null; }
96	  const r = getRoute();
97	  if (r.page === 'dashboard') renderDashboard();
98	  else if (r.page === 'specialist') renderSpecialistDetail(r.name);
99	  else if (r.page === 'task') renderLiveView(r.taskId);
100	}
101	
102	// ─── Dashboard ───────────────────────────────────────────────────────────────
103	async function renderDashboard() {
104	  app.innerHTML = '<div class="empty">載入中...</div>';
105	  try {
106	    const [statusData, spData] = await Promise.all([
107	      fetch(`${API}/api/status`).then(r => r.json()),
108	      fetch(`${API}/api/specialists`).then(r => r.json()),
109	    ]);
110	    paintDashboard(spData, statusData);
111	    startPolling(async () => {
112	      const [s, sp] = await Promise.all([
113	        fetch(`${API}/api/status`).then(r => r.json()),
114	        fetch(`${API}/api/specialists`).then(r => r.json()),
115	      ]);
116	      paintDashboard(sp, s);
117	    });
118	  } catch(e) { app.innerHTML = `<div class="empty">無法連線: ${esc(e.message)}</div>`; }
119	}
120	function paintDashboard(specialists, status) {
121	  let html = '<div class="section-title">Specialists</div><div class="card-grid">';
122	  if (specialists.length === 0) {
123	    html += '<div class="empty">尚無 specialist 設定</div>';
124	  } else {
125	    html += specialists.map(sp => {
126	      const activeHtml = sp.activeTaskId
127	        ? `<div class="active-task" data-task="${esc(sp.activeTaskId)}">⚡ 執行中...</div>` : '';
128	      return `<div class="sp-card ${sp.status}" data-name="${esc(sp.name)}">
129	        <div class="name">${esc(sp.name)}</div>
130	        <div class="model">${esc(sp.model)}</div>
131	        <div class="status-row">
132	          <span class="badge ${sp.status}">${sp.status}</span>
133	          <span>${sp.recentTaskCount} tasks/7d</span>
134	        </div>${activeHtml}</div>`;
135	    }).join('');
136	  }
137	  html += '</div>';
138	  if (status.active.length > 0) {
139	    html += '<div class="section-title">進行中</div><div class="task-list">' + status.active.map(taskCard).join('') + '</div>';
140	  }
141	  if (status.recent.length > 0) {
142	    html += '<div class="section-title">最近完成</div><div class="task-list">' + status.recent.map(taskCard).join('') + '</div>';
143	  }
144	  app.innerHTML = html;
145	  app.querySelectorAll('.sp-card[data-name]').forEach(el => {
146	    el.addEventListener('click', (e) => {
147	      const at = e.target.closest('.active-task');
148	      if (at) { navigate('#/task/' + at.dataset.task); return; }
149	      navigate('#/specialist/' + el.dataset.name);
150	    });
151	  });
152	  app.querySelectorAll('.task[data-id]').forEach(el => {
153	    el.addEventListener('click', () => navigate('#/task/' + el.dataset.id));
154	  });
155	}
156	function taskCard(t) {
157	  const elapsed = t.endTime
158	    ? Math.round((new Date(t.endTime) - new Date(t.startTime)) / 1000)
159	    : Math.round((Date.now() - new Date(t.startTime)) / 1000);
160	  const target = t.specialist || t.peer || t.type;
161	  const turns = t.turns ? `T${t.turns}` : '';
162	  return `<div class="task ${t.status}" data-id="${esc(t.taskId)}">
163	    <div class="task-header"><span class="task-target">${esc(target)}</span><span class="task-badge ${t.status}">${t.status}</span></div>
164	    <div class="task-goal">${esc(t.goal)}</div>
165	    <div class="task-meta"><span>${elapsed}s</span><span>${turns}</span><span>${t.type}</span></div>
166	  </div>`;
167	}
168	
169	// ─── Specialist Detail ───────────────────────────────────────────────────────
170	async function renderSpecialistDetail(name) {
171	  app.innerHTML = '<div class="empty">載入中...</div>';
172	  try {
173	    const detail = await fetch(`${API}/api/specialists/${encodeURIComponent(name)}`).then(r => r.json());
174	    if (detail.error) { app.innerHTML = `<div class="empty">找不到 ${esc(name)}</div>`; return; }
175	    paintSpecialistDetail(name, detail);
176	  } catch(e) { app.innerHTML = `<div class="empty">載入失敗: ${esc(e.message)}</div>`; }
177	}
178	function paintSpecialistDetail(name, detail) {
179	  const tabs = ['設定', 'Preamble', '歷史', '產出物', 'Facts'];
180	  let html = `<button class="back-btn" onclick="navigate('#/')">← Dashboard</button>`;
181	  html += `<h1><span class="dot" style="background:${detail.status==='busy'?'var(--green)':'var(--muted)'}"></span> ${esc(name)}</h1>`;
182	  html += '<div class="tabs">' + tabs.map((t, i) => `<button class="tab${i===0?' active':''}" data-tab="${i}">${t}</button>`).join('') + '</div>';
183	  html += `<div class="tab-content active" data-panel="0">
184	    <table class="config-table">
185	      <tr><td>Harness</td><td>${esc(detail.harness.command + ' ' + detail.harness.args.join(' '))}</td></tr>
186	      <tr><td>Model</td><td>${esc(detail.model)}</td></tr>
187	      <tr><td>CWD</td><td>${esc(detail.cwd)}</td></tr>
188	      <tr><td>MaxTurns</td><td>${detail.maxTurns}</td></tr>
189	      <tr><td>Timeout</td><td>${Math.round(detail.timeoutMs/60000)}m</td></tr>
190	      <tr><td>MCP</td><td>${detail.mcpServersFull.map(s=>esc(s.name)).join(', ')||'none'}</td></tr>
191	      ${detail.env?`<tr><td>Env</td><td>${esc(JSON.stringify(detail.env))}</td></tr>`:''}
192	    </table></div>`;
193	  for (let i = 1; i <= 4; i++) html += `<div class="tab-content" data-panel="${i}"><div class="empty">點擊載入...</div></div>`;
194	  app.innerHTML = html;
195	  app.querySelectorAll('.tab').forEach(btn => {
196	    btn.addEventListener('click', () => {
197	      app.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
198	      app.querySelectorAll('.tab-content').forEach(t => t.classList.remove('active'));
199	      btn.classList.add('active');
200	      const idx = btn.dataset.tab;
201	      const panel = app.querySelector(`[data-panel="${idx}"]`);
202	      panel.classList.add('active');
203	      if (idx==='1' && panel.querySelector('.empty')) loadPreamble(name, panel);
204	      if (idx==='2' && panel.querySelector('.empty')) loadHistory(name, panel);
205	      if (idx==='3' && panel.querySelector('.empty')) loadArtifacts(name, panel);
206	      if (idx==='4' && panel.querySelector('.empty')) loadFacts(name, panel);
207	    });
208	  });
209	}
210	async function loadPreamble(name, panel) {
211	  try {
212	    const r = await fetch(`${API}/api/specialists/${encodeURIComponent(name)}/preamble`);
213	    if (!r.ok) { panel.innerHTML = '<div class="empty">無 preamble 檔案</div>'; return; }
214	    const { content } = await r.json();
215	    panel.innerHTML = `<div class="preamble-view">${renderMarkdown(content)}</div>`;
216	  } catch { panel.innerHTML = '<div class="empty">載入失敗</div>'; }
217	}
218	async function loadHistory(name, panel) {
219	  try {
220	    const data = await fetch(`${API}/api/specialists/${encodeURIComponent(name)}/history`).then(r => r.json());
221	    if (data.length === 0) { panel.innerHTML = '<div class="empty">尚無歷史記錄</div>'; return; }
222	    let html = '<table class="history-table"><tr><th>Goal</th><th>Status</th><th>Turns</th><th>Time</th></tr>';
223	    data.forEach(t => {
224	      const icon = t.status==='done'?'✅':t.status==='failed'?'❌':t.status==='timeout'?'⏰':'🚫';
225	      html += `<tr><td style="max-width:300px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${esc(t.goal)}">${esc(t.goal.slice(0,60))}</td>
226	        <td>${icon} ${t.verifier?`(${t.verifier})`:''}</td><td>${t.turns??'-'}</td><td>${t.elapsedSec}s</td></tr>`;
227	    });
228	    panel.innerHTML = html + '</table>';
229	  } catch { panel.innerHTML = '<div class="empty">載入失敗</div>'; }
230	}
231	async function loadArtifacts(name, panel) {
232	  try {
233	    const data = await fetch(`${API}/api/specialists/${encodeURIComponent(name)}/artifacts`).then(r => r.json());
234	    if (data.length === 0) { panel.innerHTML = '<div class="empty">尚無產出物</div>'; return; }
235	    let html = '<div class="artifact-list">';
236	    data.forEach(a => { html += `<div class="artifact-item"><span>${esc(a.slug||a.filename)}</span><span>${a.date} · ${(a.sizeBytes/1024).toFixed(1)}KB</span></div>`; });
237	    panel.innerHTML = html + '</div>';
238	  } catch { panel.innerHTML = '<div class="empty">載入失敗</div>'; }
239	}
240	async function loadFacts(name, panel) {
241	  try {
242	    const data = await fetch(`${API}/api/specialists/${encodeURIComponent(name)}/facts`).then(r => r.json());
243	    if (data.totalCount === 0) { panel.innerHTML = '<div class="empty">尚無相關 facts</div>'; return; }
244	    let html = `<div style="font-size:.8rem;margin-bottom:8px;color:var(--muted)">共 ${data.totalCount} 筆</div>`;
245	    data.recentFacts.forEach(f => { html += `<div class="fact-item"><span class="fact-id">${esc(f.id)}</span> ${esc(f.text.slice(0,120))}</div>`; });
246	    panel.innerHTML = html;
247	  } catch { panel.innerHTML = '<div class="empty">載入失敗</div>'; }
248	}
249	
250	// ─── Live View ───────────────────────────────────────────────────────────────
251	function renderLiveView(taskId) {
252	  autoScroll = true;
253	  app.innerHTML = `<button class="back-btn" onclick="navigate('#/')">← Dashboard</button>
254	    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
255	      <h1 style="margin:0" id="liveTitle">${esc(taskId)}</h1>
256	      <button class="cancel-btn" id="liveCancel">取消</button>
257	    </div><div class="live-view">
258	      <div class="live-body" id="liveBody"></div>
259	      <div class="live-footer"><span id="liveMeta"></span><span id="liveStatus">connecting...</span></div>
260	    </div>`;
261	  const liveBody = document.getElementById('liveBody');
262	  const liveStatus = document.getElementById('liveStatus');
263	  const liveMeta = document.getElementById('liveMeta');
264	  const liveTitle = document.getElementById('liveTitle');
265	  fetch(`${API}/api/status/${encodeURIComponent(taskId)}`).then(r=>r.json()).then(t=>{
266	    if(t&&!t.error) liveTitle.textContent=t.specialist||t.peer||taskId;
267	  }).catch(()=>{});
268	  eventSource = new EventSource(`${API}/api/status/${encodeURIComponent(taskId)}/stream`);
269	  eventSource.onmessage = (e) => {
270	    const msg = JSON.parse(e.data);
271	    if (msg.type==='chunk') {
272	      const el = document.createElement('div');
273	      el.className = `chunk ${msg.role||'agent'}`;
274	      el.textContent = msg.text;
275	      liveBody.appendChild(el);
276	      if (autoScroll) liveBody.scrollTop = liveBody.scrollHeight;
277	    } else if (msg.type==='status') {
278	      liveStatus.textContent = msg.status;
279	      liveMeta.textContent = msg.turns ? `Turn ${msg.turns}` : '';
280	      if (msg.status !== 'running') { eventSource.close(); eventSource = null; }
281	    }
282	  };
283	  eventSource.onerror = () => { liveStatus.textContent='disconnected'; eventSource.close(); eventSource=null; };
284	  liveBody.addEventListener('scroll', () => { autoScroll = liveBody.scrollHeight - liveBody.scrollTop - liveBody.clientHeight < 50; });
285	  document.getElementById('liveCancel').addEventListener('click', async () => {
286	    try {
287	      const r = await fetch(`${API}/api/status/${encodeURIComponent(taskId)}/cancel`, { method: 'POST' });
288	      liveStatus.textContent = r.ok ? 'cancelled' : '無法取消（任務可能已結束）';
289	    } catch { liveStatus.textContent = '取消失敗'; }
290	  });
291	}
292	
293	// ─── Helpers ─────────────────────────────────────────────────────────────────
294	function esc(s) { return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
295	function renderMarkdown(md) {
296	  return esc(md).replace(/^### (.+)$/gm,'<h3>$1</h3>').replace(/^## (.+)$/gm,'<h2>$1</h2>')
297	    .replace(/^# (.+)$/gm,'<h1>$1</h1>').replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>')
298	    .replace(/`([^`]+)`/g,'<code>$1</code>').replace(/^- (.+)$/gm,'• $1').replace(/\n/g,'<br>');
299	}
300	function startPolling(fn) { stopPolling(); pollTimer = setInterval(fn, 3000); }
301	function stopPolling() { if (pollTimer) { clearInterval(pollTimer); pollTimer = null; } }
302	
303	// ─── Init ────────────────────────────────────────────────────────────────────
304	route();
305	</script>
306	</body>
307	</html>
