1	<!DOCTYPE html>
2	<html lang="zh-TW">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width,initial-scale=1">
6	<title>Status Monitor</title>
7	<style>
8	:root{--bg:#1a1a2e;--card:#16213e;--accent:#0f3460;--green:#4ecca3;--red:#e94560;--yellow:#f0c040;--text:#eee;--muted:#888}
9	*{margin:0;padding:0;box-sizing:border-box}
10	body{font-family:-apple-system,system-ui,sans-serif;background:var(--bg);color:var(--text);padding:12px;min-height:100vh}
11	h1{font-size:1.1rem;margin-bottom:12px;display:flex;align-items:center;gap:8px}
12	h1 .dot{width:8px;height:8px;border-radius:50%;background:var(--green);animation:pulse 1.5s infinite}
13	@keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}
14	.empty{color:var(--muted);text-align:center;margin-top:40px}
15	.task-list{display:flex;flex-direction:column;gap:8px}
16	.task{background:var(--card);border-radius:8px;padding:12px;cursor:pointer;border-left:3px solid var(--accent);transition:border-color .2s}
17	.task.running{border-left-color:var(--green)}
18	.task.failed,.task.cancelled{border-left-color:var(--red)}
19	.task.timeout{border-left-color:var(--yellow)}
20	.task.done{border-left-color:var(--muted)}
21	.task-header{display:flex;justify-content:space-between;align-items:center}
22	.task-target{font-weight:600;font-size:.9rem}
23	.task-status{font-size:.75rem;padding:2px 6px;border-radius:4px;background:var(--accent)}
