25	.task-status.failed,.task-status.cancelled{background:#3d0f0f;color:var(--red)}
26	.task-goal{font-size:.8rem;color:var(--muted);margin-top:4px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
27	.task-meta{font-size:.75rem;color:var(--muted);margin-top:6px;display:flex;gap:12px}
28	/* Live view */
29	.live-view{position:fixed;inset:0;background:var(--bg);z-index:100;display:none;flex-direction:column}
30	.live-view.open{display:flex}
31	.live-header{padding:12px;display:flex;align-items:center;gap:8px;border-bottom:1px solid var(--accent)}
32	.live-header button{background:none;border:none;color:var(--text);font-size:1.2rem;cursor:pointer}
33	.live-header .title{font-size:.9rem;font-weight:600;flex:1}
34	.live-body{flex:1;overflow-y:auto;padding:12px;font-family:'Courier New',monospace;font-size:.75rem;line-height:1.5;white-space:pre-wrap;word-break:break-all}
35	.live-body .chunk{margin-bottom:2px}
36	.live-body .chunk.thought{color:#a78bfa}
37	.live-body .chunk.tool{color:var(--yellow)}
38	.live-footer{padding:8px 12px;border-top:1px solid var(--accent);font-size:.75rem;color:var(--muted);display:flex;justify-content:space-between}
39	.cancel-btn{background:var(--red);color:#fff;border:none;border-radius:4px;padding:4px 10px;font-size:.75rem;cursor:pointer}
40	/* Section headers */
41	.section-title{font-size:.8rem;color:var(--muted);margin:16px 0 6px;text-transform:uppercase;letter-spacing:.5px}
42	/* Tabs */
43	.tabs{display:flex;gap:6px;margin-bottom:12px}
44	.tab{flex:1;padding:8px;text-align:center;background:var(--card);border:none;border-radius:6px;color:var(--muted);font-size:.85rem;cursor:pointer}
45	.tab.active{background:var(--accent);color:var(--text);font-weight:600}
46	/* Settings */
47	.cfg-group{margin-bottom:22px}
48	.cfg-group-title{margin:20px 0 10px;padding:10px 12px;border-left:4px solid #8b5cf6;border-radius:0 8px 8px 0;background:linear-gradient(90deg,rgba(139,92,246,.18),rgba(59,130,246,.06));color:#c4b5fd;font-family:Inter,"Noto Sans TC","Segoe UI",sans-serif;font-size:1rem;font-weight:750;line-height:1.35;letter-spacing:.02em}
49	.cfg-item{background:var(--card);border-radius:8px;padding:12px;margin-bottom:8px;border-left:3px solid var(--accent)}
50	.cfg-item.hot{border-left-color:var(--green)}
51	.cfg-item.restart{border-left-color:var(--yellow)}
52	.cfg-item.readonly{border-left-color:var(--muted);opacity:.9}
53	.cfg-readonly{background:var(--bg);border:1px solid var(--accent);border-radius:4px;color:var(--text);padding:6px;font-size:.8rem;font-family:'Courier New',monospace;white-space:pre-wrap;word-break:break-all;margin:0;max-height:220px;overflow:auto}
54	.cfg-label{font-weight:600;font-size:.9rem}
55	.cfg-desc{font-size:.75rem;color:var(--muted);margin:3px 0 6px}
56	.cfg-strat{font-size:.7rem;color:var(--muted);float:right}
57	.cfg-item input,.cfg-item select,.cfg-item textarea{width:100%;background:var(--bg);border:1px solid var(--accent);border-radius:4px;color:var(--text);padding:6px;font-size:.8rem;font-family:inherit}
58	.cfg-item textarea{min-height:90px;font-family:'Courier New',monospace}
59	.cfg-row{display:flex;gap:6px;margin-top:6px}
60	.cfg-save{background:var(--green);color:#08301f;border:none;border-radius:4px;padding:6px 14px;font-size:.8rem;font-weight:600;cursor:pointer;white-space:nowrap}
61	.cfg-msg{font-size:.75rem;margin-top:6px}
62	.cfg-msg.ok{color:var(--green)}
63	.cfg-msg.err{color:var(--red)}
64	.cfg-msg.warn{color:var(--yellow)}
65	.cfg-warn{font-size:.72rem;color:var(--yellow);margin-top:6px;background:#3a2f0a;border-radius:4px;padding:6px;display:none;line-height:1.4}
66	.cfg-warn.show{display:block}
67	/* Record table editor (acp-providers) */
68	.rec-table{width:100%;border-collapse:collapse;font-size:.75rem}
69	.rec-wrap{overflow-x:auto}
70	.rec-table th{color:var(--muted);text-align:left;font-weight:500;padding:2px 4px;white-space:nowrap}
71	.rec-table td{padding:2px}
72	.rec-table input,.rec-table select,.rec-table textarea{padding:4px;font-size:.72rem}
73	.rec-table textarea{min-height:58px;resize:vertical;font-family:inherit}
74	.rec-key{font-family:'Courier New',monospace}
75	.rec-del{background:var(--red);color:#fff;border:none;border-radius:4px;padding:2px 8px;cursor:pointer;width:auto!important}
76	.rec-add{background:var(--accent);color:var(--text);border:none;border-radius:4px;padding:5px 12px;font-size:.75rem;cursor:pointer;margin-top:8px}
77	.rec-move{background:var(--accent);color:var(--text);border:none;border-radius:4px;padding:2px 6px;cursor:pointer;width:auto!important;margin-right:2px}
78	.obj-bools{display:flex;gap:14px;flex-wrap:wrap;margin-bottom:8px;font-size:.78rem}
79	.obj-bools label{display:flex;align-items:center;gap:5px}.obj-bools input{width:auto}
80	</style>
81	</head>
82	<body>
83	<h1><span class="dot"></span> Status Monitor</h1>
84	<div class="tabs">
85	  <button class="tab active" id="tabTasks">📋 任務</button>
86	  <button class="tab" id="tabConfig">⚙️ 設定</button>
